    // Runs every day at 09:00 AM
    @Scheduled(cron = "0 0 9 * * *")
    @Transactional
    public void sendExpiryReminders() {
        log.info("Running Reminder Scheduler for expiring certifications...");
        LocalDateTime now = LocalDateTime.now();
        LocalDateTime threshold = now.plusDays(30);
        LocalDateTime todayStart = now.toLocalDate().atStartOfDay();
        // Optimized query: Only gets certs expiring within 30 days that haven't been reminded today
        List<Certification> expiringCerts = certificationRepository.findNeedingReminder(now, threshold, todayStart);
        int count = 0;
        for (Certification cert : expiringCerts) {
            cert.setLastReminderSent(now);
            certificationRepository.save(cert);
            notificationService.createNotification(cert.getUser(), cert, "Action Required: Expiring Certification", "Your certification \'" + cert.getTitle() + "\' is expiring soon. Please renew it.", "REMINDER");
            count++;
        }
        log.info("Sent reminders for {} expiring certifications.", count);
    }

